def rot(grid):
    R, C = len(grid), len(grid[0])
    q = deque()
    for r in range(R):
        for c in range(C):
            if grid[r][c] == 2:
                q.append((r, c))
    minutes = 0
    while q:
        for _ in range(len(q)):
            r, c = q.popleft()
            for dr, dc in ((1,0),(-1,0),(0,1),(0,-1)):
                nr, nc = r + dr, c + dc
                if 0 <= nr < R and 0 <= nc < C and grid[nr][nc] == 1:
                    grid[nr][nc] = 2
                    q.append((nr, nc))
        if q:
            minutes += 1
    return minutes

